def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    n, d = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # Hypervolume cache
    hv_cache = {}

    def compute_hv(indices: Set[int]) -> float:
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]
        if not indices:
            hv_cache[key] = 0.0
            return 0.0
        selected = points[list(indices)]
        hv = pg.hypervolume(selected)
        value = hv.compute(reference_point)
        hv_cache[key] = value
        return value

    # Contribution cache
    contrib_cache = {}

    def compute_contrib(idx: int, base_set: Set[int]) -> float:
        key = (idx, frozenset(base_set))
        if key in contrib_cache:
            return contrib_cache[key]
        if idx in base_set:
            contrib_cache[key] = 0.0
            return 0.0
        base_hv = compute_hv(base_set)
        extended = base_set | {idx}
        extended_hv = compute_hv(extended)
        contribution = extended_hv - base_hv
        contrib_cache[key] = contribution
        return contribution

    # 1. Greedy initialization (solutions of size k)
    population = []
    population_size = 20

    for _ in range(population_size):
        current = set()
        # Greedy addition
        while len(current) < k:
            best_idx = -1
            best_contrib = -np.inf
            for idx in range(n):
                if idx not in current:
                    contrib = compute_contrib(idx, current)
                    if contrib > best_contrib:
                        best_contrib = contrib
                        best_idx = idx
            if best_idx != -1:
                current.add(best_idx)
        population.append(current)

    # 2. Evolutionary search with adaptive mutation
    archive = set()  # Pareto archive: (hv, size_diff)
    max_generations = 50

    for generation in range(max_generations):
        # Evaluate population
        evaluated = []
        for sol in population:
            hv = compute_hv(sol)
            size_diff = abs(len(sol) - k)
            evaluated.append((sol, hv, size_diff))

        # Update Pareto archive (minimize size_diff, maximize hv)
        for sol, hv, size_diff in evaluated:
            dominated = False
            to_remove = []
            for arch_sol in archive:
                arch_hv = compute_hv(arch_sol)
                arch_size_diff = abs(len(arch_sol) - k)
                if arch_hv >= hv and arch_size_diff <= size_diff and (arch_hv > hv or arch_size_diff < size_diff):
                    dominated = True
                    break
                elif hv >= arch_hv and size_diff <= arch_size_diff and (hv > arch_hv or size_diff < arch_size_diff):
                    to_remove.append(arch_sol)
            if not dominated:
                archive.add(frozenset(sol))
                for rem in to_remove:
                    archive.discard(rem)

        # Selection: weighted fitness
        fitness_scores = []
        for sol, hv, size_diff in evaluated:
            # Penalize size difference, reward hypervolume
            fitness = hv - size_diff * (hv / 100 if hv > 0 else 1)
            fitness_scores.append((fitness, sol))

        fitness_scores.sort(reverse=True, key=lambda x: x[0])

        # Elitism: keep top 30%
        new_population = []
        elite_count = max(2, int(0.3 * len(fitness_scores)))
        for i in range(elite_count):
            new_population.append(set(fitness_scores[i][1]))

        # Crossover and mutation to fill population
        while len(new_population) < population_size:
            if len(fitness_scores) >= 2:
                # Tournament selection
                candidates = random.sample(fitness_scores, min(4, len(fitness_scores)))
                candidates.sort(reverse=True, key=lambda x: x[0])
                parent1 = set(candidates[0][1])
                parent2 = set(candidates[1][1])

                # Union crossover
                child = parent1 | parent2

                # Size adjustment
                if len(child) > k:
                    # Remove worst contributors
                    while len(child) > k:
                        worst_idx = -1
                        worst_contrib = np.inf
                        for idx in child:
                            contrib = compute_contrib(idx, child - {idx})
                            if contrib < worst_contrib:
                                worst_contrib = contrib
                                worst_idx = idx
                        if worst_idx != -1:
                            child.remove(worst_idx)
                elif len(child) < k:
                    # Add best contributors
                    while len(child) < k and len(child) < n:
                        best_idx = -1
                        best_contrib = -np.inf
                        for idx in range(n):
                            if idx not in child:
                                contrib = compute_contrib(idx, child)
                                if contrib > best_contrib:
                                    best_contrib = contrib
                                    best_idx = idx
                        if best_idx != -1:
                            child.add(best_idx)

                # Adaptive mutation based on size difference
                mutation_rate = 0.3 + 0.05 * abs(len(child) - k)
                if random.random() < mutation_rate:
                    if len(child) > 1 and random.random() < 0.5:
                        # Remove random point
                        child.remove(random.choice(list(child)))
                    if len(child) < n and random.random() < 0.5:
                        # Add best contributor
                        candidates = [i for i in range(n) if i not in child]
                        if candidates:
                            best_idx = -1
                            best_contrib = -np.inf
                            for idx in candidates:
                                contrib = compute_contrib(idx, child)
                                if contrib > best_contrib:
                                    best_contrib = contrib
                                    best_idx = idx
                            if best_idx != -1:
                                child.add(best_idx)

                # Ensure size exactly k
                if len(child) > k:
                    child = set(list(child)[:k])
                elif len(child) < k:
                    while len(child) < k:
                        best_idx = -1
                        best_contrib = -np.inf
                        for idx in range(n):
                            if idx not in child:
                                contrib = compute_contrib(idx, child)
                                if contrib > best_contrib:
                                    best_contrib = contrib
                                    best_idx = idx
                        if best_idx != -1:
                            child.add(best_idx)

                new_population.append(child)
            else:
                # Fallback: greedy solution
                current = set()
                while len(current) < k:
                    best_idx = -1
                    best_contrib = -np.inf
                    for idx in range(n):
                        if idx not in current:
                            contrib = compute_contrib(idx, current)
                            if contrib > best_contrib:
                                best_contrib = contrib
                                best_idx = idx
                    if best_idx != -1:
                        current.add(best_idx)
                new_population.append(current)

        population = new_population

    # 3. Select best solution from archive (size k)
    best_solution = None
    best_hv = -np.inf
    for arch_sol in archive:
        if len(arch_sol) == k:
            hv = compute_hv(arch_sol)
            if hv > best_hv:
                best_hv = hv
                best_solution = arch_sol

    # If archive has no size k, use best from population
    if best_solution is None:
        for sol in population:
            if len(sol) == k:
                hv = compute_hv(sol)
                if hv > best_hv:
                    best_hv = hv
                    best_solution = sol

    # 4. Contribution-guided local search refinement
    if best_solution is not None:
        current_set = set(best_solution)
        improved = True
        while improved:
            improved = False
            current_hv = compute_hv(current_set)
            # Try all single swaps
            for s_idx in list(current_set):
                for r_idx in range(n):
                    if r_idx not in current_set:
                        new_set = (current_set - {s_idx}) | {r_idx}
                        new_hv = compute_hv(new_set)
                        if new_hv > current_hv:
                            current_set = new_set
                            improved = True
                            break
                if improved:
                    break

    # Fallback: greedy if no solution found
    if best_solution is None:
        current_set = set()
        while len(current_set) < k:
            best_idx = -1
            best_contrib = -np.inf
            for idx in range(n):
                if idx not in current_set:
                    contrib = compute_contrib(idx, current_set)
                    if contrib > best_contrib:
                        best_contrib = contrib
                        best_idx = idx
            if best_idx != -1:
                current_set.add(best_idx)
        best_solution = current_set

    selected_indices = list(best_solution)
    selected_points = points[selected_indices]
    return selected_points

